INSERT INTO ejes_estrategicos (id, roadmap_id, nombre, descripcion, color, posicion) VALUES ('E2', '7a467b5c-0622-442f-82d3-b3ce8ff11c87', 'Modernización tecnológica de ETNA', 'Reducir deuda técnica y habilitar la evolución futura del sistema mediante la migración de módulos clave.', '#1976D2', 1);
INSERT INTO ejes_estrategicos (id, roadmap_id, nombre, descripcion, color, posicion) VALUES ('E3', '7a467b5c-0622-442f-82d3-b3ce8ff11c87', 'Gestión integral de activos y mantenimiento', 'Mejorar la planificación, coherencia y explotación del ciclo de vida de los activos gestionados en ETNA.', '#388E3C', 2);
INSERT INTO ejes_estrategicos (id, roadmap_id, nombre, descripcion, color, posicion) VALUES ('E4', '7a467b5c-0622-442f-82d3-b3ce8ff11c87', 'Integración con el ecosistema ENAIRE', 'Posicionar ETNA como plataforma integrada dentro del ecosistema corporativo.', '#F57C00', 3);
INSERT INTO ejes_estrategicos (id, roadmap_id, nombre, descripcion, color, posicion) VALUES ('E5', '7a467b5c-0622-442f-82d3-b3ce8ff11c87', 'Explotación del dato e inteligencia de negocio', 'Evolucionar ETNA hacia un sistema de apoyo a la decisión basado en datos.', '#7B1FA2', 4);
